text:
&-capsule {
  display: inline-block;
  border-radius: @corner-radius-md;
  border-radius: var(--am-button-capsule-corner, @corner-radius-md);
  padding: @size-1 @size-3;
  padding: var(--am-button-capsule-padding-v, @size-1) var(--am-button-capsule-padding-h, @size-3);
  &-large {
    font-size: @font-size-subtitle;
    font-size: var(--am-button-capsule-size-l, @font-size-subtitle);
    &-minwidth {
      min-width: 168 * @pixelSize;
    }
  }
  &-medium {
    font-size: @font-size-content;
    font-size: var(--am-button-capsule-size-m, @font-size-content);
    &-minwidth {
      min-width: 152 * @pixelSize;
    }
  }
  &-small {
    font-size: @font-size-subcontent;
    font-size: var(--am-button-capsule-size-s, @font-size-subcontent);
    &-minwidth {
      min-width: 144 * @pixelSize;
    }
  }
}

& &-header {
  display: flex;
  align-items: center;
  color: @color-text-title;
  color: var(--am-terms-content-color, @color-text-title);
  margin-bottom: @size-5;
  margin-bottom: var(--am-terms-content-margin, @size-5);
  .am-checkbox {
    margin-right: @h-spacing-standard;
    margin-right: var(--am-terms-checkbox-margin, @h-spacing-standard);
  }
  .text {
    font-size: @font-size-subtitle;
    font-size: var(--am-terms-content-font-size, @font-size-subtitle);
    line-height: @icon-size-sm;
    line-height: var(--am-terms-content-line-height, @icon-size-sm);
    flex: 1;
    .link {
      color: @color-text-primary;
      color: var(--am-terms-link-color, @color-text-primary);
      display: inline;
    }
  }
}

&-right-radius {
  overflow: hidden;
  .am-swipe-btn {
    margin-right: 2 * @pixelSize;
    &:nth-child(2) {
      border-radius: @corner-radius-lg 0 0 @corner-radius-lg;
      border-radius: var(--am-swipeAction-item-radius, @corner-radius-lg) 0 0 var(--am-swipeAction-item-radius, @corner-radius-lg);
    }
    &:last-child {
      margin-right: 0;
      border-radius: 0 @corner-radius-lg @corner-radius-lg 0;
      border-radius: 0 var(--am-swipeAction-item-radius, @corner-radius-lg) var(--am-swipeAction-item-radius, @corner-radius-lg) 0;
    }
    &:nth-child(2):last-child {
      border-radius: @corner-radius-lg;
      border-radius: var(--am-swipeAction-item-radius, @corner-radius-lg);
    }
  }
}

@media (hover: hover) and (pointer: fine) {
    // 编辑时，当前输入行样式
    @{writeOnHTML}>:not(@{hr_MdHr})+ol>li:hover::before,
    @{writeOnHTML} @{quote_details}>:not(@{hr_MdHr})+ol>li:hover::before,
    // 针对列表行的 hover 样式
    @{writeOnEditing}>:not(@{hr_MdHr})+ol>li.md-focus-container::before,
    @{writeOnEditing} @{quote_details}>:not(@{hr_MdHr})+ol>li.md-focus-container::before {
        .genOrderList_hoverBeforeForStyle(@style) when (@style = solid) {
            color: @buttonForeHoverColor !important;
            background-color: var(--a-o-c);
            box-shadow: none;
        }
        .genOrderList_hoverBeforeForStyle(@style) when (@style = line) {
            color: var(--a-o-c) !important;
            background-color: var(--ac-t2-a);
            box-shadow: 0 0 0 1px var(--a-o-c) inset; // 不用 border 的原因是渲染会上移 1px
        }
        .genOrderList_hoverBeforeForStyle(@style);
    }
}

input {
  &:not([type='radio'], [class*='tiny-']) {
    border: 1px solid var(--tv-Grid-input-border-color);
    border-radius: var(--tv-Grid-input-border-radius);
    color: var(--tv-Grid-input-text-color);
    background-color: var(--tv-Grid-input-bg-color);
    font-size: var(--tv-Grid-input-font-size);
    height: var(--tv-Grid-input-height);
    line-height: var(--tv-Grid-input-height);
    padding: var(--tv-Grid-input-padding-x) var(--tv-Grid-input-padding-y);
    outline: 0;
    display: inline-block;
    box-sizing: border-box;
    appearance: none;
    transition: border-color 0.2s cubic-bezier(0.645, 0.045, 0.355, 1);
    margin-right: 24px;

    &:hover,
    &:focus,
    &:active {
      outline: 0;
      border-color: var(--tv-Grid-input-border-color-hover);
    }
  }
}

&:not([type='radio'], [class*='tiny-']) {
  border: 1px solid var(--tv-Grid-input-border-color);
  border-radius: var(--tv-Grid-input-border-radius);
  color: var(--tv-Grid-input-text-color);
  background-color: var(--tv-Grid-input-bg-color);
  font-size: var(--tv-Grid-input-font-size);
  height: var(--tv-Grid-input-height);
  line-height: var(--tv-Grid-input-height);
  padding: var(--tv-Grid-input-padding-x) var(--tv-Grid-input-padding-y);
  outline: 0;
  display: inline-block;
  box-sizing: border-box;
  appearance: none;
  transition: border-color 0.2s cubic-bezier(0.645, 0.045, 0.355, 1);
  margin-right: 24px;

  &:hover,
  &:focus,
  &:active {
    outline: 0;
    border-color: var(--tv-Grid-input-border-color-hover);
  }
}

&-shimmer {
  border-radius: 8px;
  background: linear-gradient(
    90deg,
    color-mix(in srgb, var(--home-muted, #6b6b72) 10%, transparent) 25%,
    color-mix(in srgb, var(--home-muted, #6b6b72) 20%, transparent) 50%,
    color-mix(in srgb, var(--home-muted, #6b6b72) 10%, transparent) 75%
  );
  background-size: 200% 100%;
  animation: avocado-shimmer 1.4s ease-in-out infinite;

  &--avatar {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    margin: 0 auto 16px;
  }

  &--name   { width: 110px; height: 14px; margin: 0 auto 10px; }
  &--role   { width: 70px;  height: 20px; margin: 0 auto 10px; border-radius: 20px; }
  &--bio    { width: 85%;   height: 10px; margin: 0 auto 6px; border-radius: 6px; }
  &--stats  { width: 60%;   height: 10px; margin: 0 auto;     border-radius: 6px; }
}
